// Products Object 
var products = {
    brand: 'Iphone',
    model: '17 Pro',
    price: 399.20,
    purchase: false,
    // Updates price and marks purchase item as true
    // Console the update object properties
    buy: function (price) {
        products.price = price
        products.purchase = true;
        console.log(this)
    }
}

// Console log the default products object 
console.log(products)

// Ask the user to change the Phone Brand and its model
// and update the model property  and brand of the object
var newBrand = prompt('Choose new Phone Brand',`${products.brand}`)
products.brand = newBrand; 

var newModel = prompt('Choose the Model',`${products.model}`)
products.model = newModel; 

// Update the price of the model
products.buy(345.90);
